#include<bits/stdc++.h>
#define LL long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 5e4+5;
struct node{LL x,y,to;}a[N];
LL n,G,B,D;stack<int> st;
bool cmp(node d1,node d2){return d1.x<d2.x;}
LL Answer(){
    LL ans=0;B-=a[1].x;
    for(int i=1;i<n;){
        if(B<0)return -1;
        if(a[a[i].to].x-a[i].x<=G){
            LL tmp=max(0ll,a[a[i].to].x-a[i].x-B);
            ans+=tmp*a[i].y,B+=tmp-(a[a[i].to].x-a[i].x),i=a[i].to;
        }
        else ans+=(G-B)*a[i].y,B=G-(a[i+1].x-a[i].x),i++;
    }
    return ans;
}
int main(){
    cin>>n>>G>>B>>D;
    for(int i=1;i<=n;i++)cin>>a[i].x>>a[i].y;
    sort(a+1,a+n+1,cmp);a[++n]={D,0,0};
    for(int i=1;i<=n;st.push(i),i++)
        while(!st.empty()&&a[i].y<=a[st.top()].y)
            a[st.top()].to=i,st.pop();
    cout<<Answer()<<"\n";
    return 0;
}
